let route={view:"dashboard",id:null};
const state={}; // per service working state

/* Saved rows from an older app version can have a different schema (renamed columns).
   Only use saved rows if they match the current card's key column; otherwise fall back to built-ins. */
function validSavedRows(rows,keyCol){
  return Array.isArray(rows) && rows.length>0 && rows.some(r=>r && r[keyCol]!=null && r[keyCol]!=="");
}
function getRate(svc){
  if(!svc.rate) return null;
  const saved=loadSavedRates(svc.id);
  if(validSavedRows(saved,svc.rate.keyCol)) return {rows:saved.map(r=>({...r}))};
  return {rows:svc.rate.rows.map(r=>({...r}))};
}
function getRateCards(svc){
  if(!svc.rateCards) return null;
  const o={};
  svc.rateCards.forEach(c=>{ const saved=loadSavedRates(svc.id+":"+c.id);
    o[c.id]={rows:(validSavedRows(saved,c.keyCol)?saved:c.rows).map(r=>({...r}))}; });
  return o;
}

