/* ============================================================
   PRICING PART — cost + margin → sell rate cards
   Services: FedEx Singapore (IP/Pak/Connect Plus/Return),
             AME (Bpost) full cost build-up, QSM (ePAC + Speedpost)
   Engines verified against the CALC files' own cached values.
   ============================================================ */
const _AME_ORIGS=[["SIN","exSIN"],["KUL","exKUL"],["BKK","exBKK"],["SGN","exSGN"]];
const PRICING=[{id:"pfedex",name:"FedEx Singapore"}]
  .concat(_AME_ORIGS.map(o=>({id:"pame_"+o[0],name:"AME "+o[1],ameOrig:o[0]})))
  .concat([{id:"pqsm",name:"QSM (Singpost)"}]);
const _PRC_FDXPROD=[["IP","FedEx IP (International Priority)"],["PAK","IP Pak rate"],["CP","Connect Plus"],["RET","Economy Import (Return)"]];
let PRS={pfedex:{tab:"build",prod:"IP",custName:"",filter:""},
         pqsm:{tab:"build",sub:"epac",margin:8,pickup:0.44,spdMargin:5,custName:""}};
_AME_ORIGS.forEach(o=>{ PRS["pame_"+o[0]]={tab:"build",orig:o[0],typ:"TRACKED",rte:"Hub",routeBy:{},be:"",margin:4,version:"AME.CUS."+o[0]+".V1.0.2026",filter:""}; });
function prGet(key,def){ const s=loadSavedRates("pricing:"+key); return (s==null||(s&&s.__none))?def:s; }
function prSet(key,val){ saveRatesFor("pricing:"+key,(val==null)?{__none:1}:val); }
function prNum(v,d){ const n=Number(v); return isFinite(n)?n:(d||0); }

/* ---------------- FedEx engine ---------------- */
function prFdxParams(prod){ const base={..._PRC_FDX[prod].params}; const o=prGet("fdx_params_"+prod,null); return o?Object.assign(base,o):base; }
function prFdxNetTbl(prod){ const d=_PRC_FDX[prod]; const o=prGet("fdx_net_"+prod,null);
  return o||{weights:d.weights.slice(),zones:d.zones.slice(),net:d.net.map(r=>r.slice())}; }
function prFdxSell(prod){
  const d=_PRC_FDX[prod], p=prFdxParams(prod), NT=prFdxNetTbl(prod);
  const zi={}; NT.zones.forEach((z,i)=>{ if(zi[String(z).trim().toUpperCase()]===undefined) zi[String(z).trim().toUpperCase()]=i; });
  const wi={}; NT.weights.forEach((w,i)=>{ if(wi[+w]===undefined) wi[+w]=i; });
  const zByName={}; d.zmap.forEach(m=>{ const k=String(m[0]).trim().toLowerCase(); if(zByName[k]===undefined) zByName[k]=m[1]; });
  const sellW=NT.weights.map(Number);
  const rows=d.countries.map(c=>{
    const code=c[0], name=c[2];
    const zone=zByName[String(name||"").trim().toLowerCase()];
    const zii=(zone!=null)?zi[String(zone).trim().toUpperCase()]:null;
    const vals=sellW.map(w=>{
      if(zii==null||wi[w]==null) return null;
      const net=NT.net[wi[w]][zii]; if(typeof net!=="number") return null;
      const s=((net*(1+prNum(p.vendor)))+prNum(p.clearanceKg)*w+prNum(p.linehaulKg)*w+prNum(p.handlingPc)+prNum(p.pickupPc)+prNum(p.pickupKg)*w)*(1+prNum(p.margin))*prNum(p.fx,1);
      return d.rounded?round2(s):s; });
    return {code,name,zone:zone||"",cp:c[1],vals};
  });
  return {weights:sellW,rows,params:p,rounded:d.rounded};
}

/* ---------------- AME engine (mirror of the verified CALC) ---------------- */
/* Cost-aggregate columns to recompute rather than echo from the cached literals (see prAmeCompute). */
const _AME_RECALC=["R","AA","AB","AL","AU","AV","BC","BD","BK","BL","BO","BP","BY","BZ"];
function _prlk(v){ return (typeof v==="string")?v.trim().toLowerCase():v; }
function prAmeTables(){
  return { combined:prGet("ame_combined",_PRC_AME.combined), combinedU:prGet("ame_combinedU",_PRC_AME.combinedU),
           currency:prGet("ame_currency",_PRC_AME.currency), pickup:prGet("ame_pickup",_PRC_AME.pickup) };
}
function prAmeRows(orig){ const o=prGet("ame_rows_"+orig,null); return o||_PRC_AME.origins[orig].rows; }
function prAmeCompute(orig){
  const T=prAmeTables();
  const FXMAP={}; T.currency.forEach(r=>{ const k=_prlk(r[1]); if(typeof k==="string"&&FXMAP[k]===undefined) FXMAP[k]=r[5]; });
  const CMBBY={},CMBAY={},CMBUAY={},PUPMAP={};
  T.combined.forEach(r=>{ const k=_prlk(r[2]); if(k!=null&&CMBBY[k]===undefined) CMBBY[k]=r;
    const a=_prlk(r[1]); if(a!=null&&CMBAY[a]===undefined) CMBAY[a]=r; });
  T.combinedU.forEach(r=>{ const a=_prlk(r[1]); if(a!=null&&CMBUAY[a]===undefined) CMBUAY[a]=r; });
  T.pickup.forEach(r=>{ const k=_prlk(r[1]); if(typeof k==="string"&&PUPMAP[k]===undefined) PUPMAP[k]=r; });
  const XERR={pr:1};
  const num_=v=>{ if(v==null) return 0; if(typeof v==="number") return v;
    if(typeof v==="string"){ if(v.trim()==="") throw XERR; const n=Number(v); if(isFinite(n)) return n; throw XERR; } throw XERR; };
  const fmt_=v=>{ if(v==null) return ""; return String(v); };
  const FX=c=>{ const k=_prlk(c); if(typeof k!=="string"||FXMAP[k]===undefined) throw XERR; const r=FXMAP[k]; return (r==null)?0:num_(r); };
  const CMB=(k,n)=>{ const r=CMBBY[_prlk(k)]; if(!r) throw XERR; return r[1+n]; };
  const CMBA=d=>{ const r=CMBAY[_prlk(d)]; if(!r) throw XERR; return r[5]; };
  const CMBUA=d=>{ const r=CMBUAY[_prlk(d)]; if(!r) throw XERR; return r[5]; };
  const PUP=(a,n)=>{ const r=PUPMAP[_prlk(a)]; if(!r) throw XERR; return r[n]; };
  const IFE=(f,alt)=>{ try{ const v=f(); if(typeof v==="number"&&!isFinite(v)) return (alt!==undefined?alt:0); return v; }catch(e){ return (alt!==undefined?alt:0); } };
  const seq=(a,b)=>_prlk(a)===_prlk(b);
  const COLS=["R","AA","AB","AL","AU","AV","BC","BD","BF","BH","BI","BJ","BK","BL","BO","BP","BQ","BR","BS","BU","BV","BW","BX","BY","BZ","CA","CB","CC"];
  const out=[];
  prAmeRows(orig).forEach(row=>{
    /* The shipped data caches per-row cost aggregates as literals; strip them so the totals are always
       RECOMPUTED from the (editable) components + lookups. Verified to reproduce the CALC BY/BZ 100% for
       all origins, and it makes edits (leg panel, grid, last-mile) actually flow through to the total.
       Lookup/product/pickup literals (BF,BH,BI,BJ,BQ..BX,CA,CB,CC) are preserved — they carry real overrides. */
    const IN={...(row.in||{})}, CV={...(row.cv||{})}; _AME_RECALC.forEach(c=>{ delete IN[c]; delete CV[c]; }); const memo={};
    let FORM;
    function G(c){ if(Object.prototype.hasOwnProperty.call(memo,c)) return memo[c];
      if(IN[c]!==undefined) return IN[c];   /* a literal cell in the CALC IS the value — it overrides the column formula (e.g. BKK literal pickup, hardcoded BF/DSP product) */
      if(FORM[c]){ memo[c]=null; const v=FORM[c](); memo[c]=v; return v; }
      if(CV[c]!==undefined) return CV[c]; return null; }
    const N=c=>num_(G(c));
    FORM={
      R:()=>IFE(()=>(N("N")+N("O")/N("L"))*FX(G("P"))*(1+N("M"))),
      AA:()=>IFE(()=>N("W")*FX(G("Z"))),
      AB:()=>IFE(()=>((N("Y")/N("U"))+N("X"))*FX(G("Z"))*(1+N("V"))),
      AL:()=>IFE(()=>(N("AH")+N("AI")/N("AF"))*FX(G("AJ"))*(1+N("AG"))),
      AU:()=>IFE(()=>N("AQ")*FX(G("AT"))),
      AV:()=>IFE(()=>((N("AS")/N("AO"))+N("AR"))*FX(G("AT"))*(1+N("AP"))),
      BC:()=>IFE(()=>N("AX")*FX(G("BA"))),
      BD:()=>IFE(()=>(N("AZ")+IFE(()=>{ const q=N("AY")/N("BB"); if(!isFinite(q)) throw XERR; return q; }))*FX(G("BA"))),
      BF:()=>fmt_(G("CB"))+" "+fmt_(G("I")),
      BH:()=>CMB(G("CA"),14), BI:()=>CMB(G("CA"),15), BJ:()=>CMB(G("CA"),5),
      BK:()=>IFE(()=>FX(G("BJ"))*N("BH")),
      BL:()=>IFE(()=>FX(G("BJ"))*N("BI")*(1+N("BG"))),
      BO:()=>N("AA")+N("AK")+N("AU")+N("BC")+N("BK"),
      BP:()=>N("R")+N("AB")+N("AL")+N("AV")+N("BD")+N("BL"),
      BQ:()=>PUP(G("A"),2), BR:()=>PUP(G("A"),3), BS:()=>PUP(G("A"),4), BU:()=>PUP(G("A"),6), BV:()=>PUP(G("A"),7),
      BW:()=>IFE(()=>N("BQ")*FX(G("BV"))),
      BX:()=>IFE(()=>(IFE(()=>{ const q=N("BS")/N("BT"); if(!isFinite(q)) throw XERR; return q; })+N("BR")*(1+N("BU")))*FX(G("BV"))),
      BY:()=>N("AA")+N("AK")+N("AU")+N("BC")+N("BK")+N("BW"),
      BZ:()=>N("R")+N("AB")+N("AL")+N("AV")+N("BD")+N("BL")+N("BX"),
      CA:()=>fmt_(G("BE"))+fmt_(G("BF"))+fmt_(G("D"))+fmt_(G("G")),
      CB:()=>seq(G("BE"),"Bpost")?CMBA(G("D")):(seq(G("BE"),"BPost Unsorted")?CMBUA(G("D")):"NA"),
      CC:()=>seq(G("CB"),"Dragon Scan")?"TRACKED":(seq(G("CB"),"Minipak")?"UNTRACKED":"NA"),
    };
    const res={};
    COLS.forEach(c=>{ try{ res[c]=G(c); }catch(e){ res[c]="#ERR"; } });
    out.push({r:row.r,in:IN,cv:CV,out:res});
  });
  return out;
}
function prAmeBEs(orig){ const s=new Set(); prAmeRows(orig).forEach(r=>{ if(r.in&&r.in.BE) s.add(String(r.in.BE)); }); return [...s]; }
/* Countries allowed to be quoted Direct (others are Hub only). Editable & saved; defaults to the 6 owner-approved lanes. */
const _AME_DIRECT_DEF=["AU","BE","FR","GB","NL","NZ"];
function prAmeDirectList(){ const s=prGet("ame_direct_countries",null); return (Array.isArray(s)&&s.length)?s.map(x=>String(x).trim().toUpperCase()):_AME_DIRECT_DEF.slice(); }
function prAmeDirectSet(){ return new Set(prAmeDirectList()); }
function prAmeSetDirect(str){ const arr=String(str||"").split(/[,\s;]+/).map(x=>x.trim().toUpperCase()).filter(Boolean); prSet("ame_direct_countries",arr); render(); }
function prAmeCards(orig,marginPct,beFilter,typFilter,routePref,routeByCode){
  const comp=prAmeCompute(orig);
  const tplByName={}; _PRC_TPL.ameCardDefaults.forEach(t=>{ const k=String(t[1]).trim().toLowerCase(); if(tplByName[k]===undefined) tplByName[k]=t; });
  const m=1+prNum(marginPct)/100;
  const rby=routeByCode||{};
  /* group candidate rows by destination+max-weight; a destination can exist both Direct and Hub
     (with different last-mile cost). Pick the route per destination: a per-country override wins,
     else the card default (routePref), else whatever route that destination actually has. */
  const groups={}, order=[];
  comp.forEach(c=>{
    const IN=c.in;
    if(beFilter && String(IN.BE||"").trim().toLowerCase()!==String(beFilter).trim().toLowerCase()) return;
    if(typFilter && c.out.CC!==typFilter) return;
    const key=IN.D+"|"+IN.G;
    if(!groups[key]){ groups[key]=[]; order.push(key); }
    groups[key].push(c);
  });
  const dirSet=prAmeDirectSet();
  const rows=[];
  order.forEach(key=>{
    const g0=groups[key];
    const D=g0[0].in.D;
    const allowDir=dirSet.has(String(D).trim().toUpperCase());
    /* drop Direct lanes for countries not on the Direct-allowed list, so they stay Hub only */
    let g=allowDir?g0:g0.filter(x=>String(x.in.I||"").trim().toLowerCase()!=="direct");
    if(!g.length) g=g0;
    const avail=[]; g.forEach(x=>{ const r=String(x.in.I||"").trim(); if(r&&avail.indexOf(r)<0) avail.push(r); });
    const want=String((rby[D]!=null&&rby[D]!=="")?rby[D]:(routePref||"")).trim().toLowerCase();
    let c=g[0];
    if(want){ const hit=g.find(x=>String(x.in.I||"").trim().toLowerCase()===want); if(hit) c=hit; }
    const IN=c.in, name=IN.E, maxw=IN.G;
    const t=tplByName[String(name||"").trim().toLowerCase()];
    rows.push({code:D,name:(t?t[1]:name),typ:c.out.CC,route:(String(IN.I||"").trim()||(t?t[2]:"")),routes:avail,maxw,dtime:(t?t[4]:""),
      pc:_ru2(prNum(c.out.BY)*m), kg:_ru2(prNum(c.out.BZ)*m), costPc:prNum(c.out.BY), costKg:prNum(c.out.BZ)});
  });
  rows.sort((a,b)=>String(a.name).localeCompare(String(b.name)));
  return rows;
}
/* How many destinations (at the given type) exist BOTH Direct and Hub — i.e. the route toggle changes their rate. */
function prAmeDualRoute(orig,typFilter){
  const comp=prAmeCompute(orig), grp={}, dirSet=prAmeDirectSet();
  comp.forEach(c=>{ if(typFilter && c.out.CC!==typFilter) return;
    const r=String(c.in.I||"").trim().toLowerCase();
    if(r==="direct" && !dirSet.has(String(c.in.D).trim().toUpperCase())) return; /* Direct not allowed here */
    const k=c.in.D+"|"+c.in.G; (grp[k]=grp[k]||new Set()).add(r); });
  let n=0; Object.values(grp).forEach(s=>{ if(s.has("direct")&&s.has("hub")) n++; }); return n;
}

/* ---------------- QSM engines ---------------- */
function _ru2(x){ if(!(x>0)) return 0; return Math.ceil(Math.round(x*1e6)/1e4-1e-9)/100; }
function prEpacCost(){ return prGet("epac_cost",_PRC_EPAC.cost); }
function prEpacSell(marginPct,pickupPc){
  const m=1+prNum(marginPct)/100;
  return prEpacCost().map(c=>({zone:c[0],name:c[1],code:c[2],item:c[3],kg:c[4],
    sItem:(typeof c[3]==="number")?round2(_ru2(c[3]*m)+prNum(pickupPc)):null,
    sKg:(typeof c[4]==="number")?_ru2(c[4]*m):null}));
}
function prSpdCost(){ return {countries:_PRC_SPD.countries, weights:prGet("spd_weights",_PRC_SPD.weights), cost:prGet("spd_cost",_PRC_SPD.cost)}; }
function prSpdSell(marginPct){
  const d=prSpdCost(), m=1+prNum(marginPct)/100;
  return {countries:d.countries,weights:d.weights,
    rows:d.cost.map(r=>r.map(v=>(typeof v==="number")?_ru2(v*m):null))};
}

/* ---------------- Pricing UI ---------------- */
function renderPricing(v,id){
  if(!PRS[id]) id="pfedex";
  const P=PRS[id];
  const svc=PRICING.find(s=>s.id===id);
  setTitle(svc.name,"Pricing · "+svc.name);
  const tabs=`<div class="tabs" style="margin-bottom:14px">
    <button class="tab ${P.tab==='build'?'active':''}" onclick="prTab('${id}','build')">⚙ Build rate card</button>
    <button class="tab ${P.tab==='cost'?'active':''}" onclick="prTab('${id}','cost')">▤ Cost cards</button></div>`;
  let h=tabs;
  if(id==="pfedex") h+= P.tab==="build"?prFdxBuildHtml():prFdxCostHtml();
  else if(id.slice(0,5)==="pame_") h+= P.tab==="build"?prAmeBuildHtml(id):prAmeCostHtml(id);
  else h+= P.tab==="build"?prQsmBuildHtml():prQsmCostHtml();
  v.innerHTML=h;
}
function prTab(id,t){ PRS[id].tab=t; render(); }
function prSetS(id,k,v){ PRS[id][k]=v; render(); }
function prInp(id,k,v){ PRS[id][k]=v; } /* no re-render while typing */
function prAmeSetRoute(id,code,val){ const P=PRS[id]; if(!P.routeBy) P.routeBy={}; P.routeBy[code]=val; render(); }
function prAmeResetRoutes(id){ PRS[id].routeBy={}; render(); }

