/* Upload a Bpost postal cost card (…Dragon Scan / Minipak Scan sheets: NAME | ISO | KG | ITEM)
   and refresh the matching last-mile Item(/pc) & KG(/kg) rates in COMBINED.
   Route (Hub vs Direct) is taken from the file name — these cards are Hub unless the name says Direct.
   MiniPak EU Prior / MiniPak TT sheets are alternate products the CALC does not use for Hub last mile, so they are skipped. */
/* Bulk-load a Bpost last-mile workbook. Handles multi-sheet "all rate" files:
   each sheet's product (Dragon Scan=tracked / MiniPak=untracked) and route (Direct/Hub) are read
   from the sheet name (falling back to the file name for route), and the ISO/KG/ITEM columns are
   auto-detected from the header, so different sheet layouts all load. Updates the shared COMBINED
   last-mile Item(/pc) & KG(/kg); route (Direct vs Hub) is kept separate. */
function prAmeLmLoad(inp){
  const f=inp.files&&inp.files[0]; if(!f) return;
  const fnameRoute=/direct/i.test(String(f.name||""))?"Direct":"Hub";
  function classify(sn){ const s=String(sn).toLowerCase();
    let fam=null; if(/dragon/.test(s)) fam="Dragon Scan"; else if(/mini\s*pak|minipak/.test(s)) fam="MiniPak";
    if(!fam) return null;
    const route=/direct/.test(s)?"Direct":(/hub/.test(s)?"Hub":fnameRoute);
    return {fam,route}; }
  function findCols(aoa){ let iso=-1,kg=-1,item=-1;
    for(let i=0;i<Math.min(aoa.length,8);i++){ (aoa[i]||[]).forEach((v,j)=>{ const t=String(v==null?"":v).trim().toLowerCase();
      if(t==="iso"&&iso<0) iso=j; else if(t==="kg"&&kg<0) kg=j; else if(t==="item"&&item<0) item=j; }); }
    return {iso,kg,item}; }
  const rd=new FileReader();
  rd.onload=e=>{ try{
    const wb=XLSX.read(new Uint8Array(e.target.result),{type:"array"});
    const parsed=[], skipped=[];
    wb.SheetNames.forEach(sn=>{
      const cl=classify(sn); if(!cl){ skipped.push(sn); return; }
      const aoa=sheetRows(wb.Sheets[sn]); const c=findCols(aoa);
      if(c.iso<0||c.kg<0||c.item<0){ skipped.push(sn+" (no ISO/KG/ITEM header)"); return; }
      const map={};
      aoa.forEach(r=>{ const iso=r[c.iso], kg=Number(r[c.kg]), item=Number(r[c.item]);
        if(typeof iso==="string"&&iso.trim()!==""&&iso.trim().length<=3&&isFinite(kg)&&isFinite(item))
          map[iso.trim().toUpperCase()]={item,kg}; });
      if(Object.keys(map).length) parsed.push({sheet:sn,fam:cl.fam,route:cl.route,map}); else skipped.push(sn+" (no rows)");
    });
    if(!parsed.length){ alert("No recognizable Bpost rate sheets found. A sheet name must contain 'Dragon Scan' or 'MiniPak', with columns headed ISO / KG / ITEM."); return; }
    /* Apply MiniPak "EU Prior" AFTER "TT" so EU-Prior rates win for their (EU) countries, TT covers the rest. */
    parsed.sort((a,b)=>(/eu\s*prior/i.test(a.sheet)?1:0)-(/eu\s*prior/i.test(b.sheet)?1:0));
    const T=prAmeTables(); const tbl=JSON.parse(JSON.stringify(T.combined));
    const report=[];
    parsed.forEach(p=>{ let updated=0, unmatched=0; const misses=[];
      Object.keys(p.map).forEach(iso=>{ let hit=false;
        tbl.forEach(r=>{ if(!(r[1]&&String(r[1]).length<=3)) return;
          const rRoute=/direct/i.test(String(r[4]||""))?"Direct":"Hub";
          if(String(r[5]||"").trim().toLowerCase()===p.fam.toLowerCase() && String(r[1]).trim().toUpperCase()===iso && rRoute===p.route){
            r[15]=p.map[iso].item; r[16]=p.map[iso].kg; updated++; hit=true; } });
        if(!hit){ unmatched++; if(misses.length<6) misses.push(iso); } });
      report.push({sheet:p.sheet,fam:p.fam,route:p.route,n:Object.keys(p.map).length,updated,unmatched,misses}); });
    prSet("ame_combined",tbl);
    const tot=report.reduce((a,r)=>a+r.updated,0);
    let msg=tot+" last-mile rate(s) updated — "+report.map(r=>r.sheet+" → "+r.fam+" "+r.route+": "+r.updated+"/"+r.n+(r.unmatched?(", "+r.unmatched+" no lane e.g. "+r.misses.slice(0,3).join("/")):"" )).join("; ");
    if(skipped.length) msg+=". Skipped: "+skipped.join(", ");
    toastP(msg+"."); render();
  }catch(err){ alert("Could not read the file: "+err.message); } };
  rd.readAsArrayBuffer(f);
}

/* ---- QSM UI ---- */
function prQsmBuildHtml(){
  const P=PRS.pqsm;
  const sub=`<div class="tabs" style="margin-bottom:12px">
    <button class="tab ${P.sub==='epac'?'active':''}" onclick="prSetS('pqsm','sub','epac')">ePAC</button>
    <button class="tab ${P.sub==='spd'?'active':''}" onclick="prSetS('pqsm','sub','spd')">Speedpost (SDI · EU)</button></div>`;
  if(P.sub==="epac"){
    const rows=prEpacSell(P.margin,P.pickup);
    return sub+`<div class="card"><div class="step">Pricing · QSM ePAC</div><h3>Build an ePAC sell rate card</h3>
      <p class="sub">Sell item = ROUNDUP(cost × (1+margin), 2) + pickup/pc · Sell kg = ROUNDUP(cost × (1+margin), 2). Your generic card = 8% + $0.44 pickup; your SG Link card = 5%, no pickup.</p>
      <div class="filters" style="display:flex;gap:10px;flex-wrap:wrap;align-items:flex-end">
        <label>Margin %<br><input type="number" step="0.1" style="width:80px" value="${P.margin}" onchange="prSetS('pqsm','margin',Number(this.value))"></label>
        <label>Pickup /pc<br><input type="number" step="0.01" style="width:80px" value="${P.pickup}" onchange="prSetS('pqsm','pickup',Number(this.value))"></label>
        <label>Customer (file name)<br><input type="text" style="width:160px" placeholder="e.g. SG Link" value="${esc(P.custName||"")}" onchange="prInp('pqsm','custName',this.value)"></label>
        <button class="primary" onclick="prDlEpacCard()">⭳ Customer rate card</button>
        <button class="subtle" onclick="prDlEpacCalc()">⭳ CALC with formulas</button>
      </div>
      <div class="tbl-scroll" style="max-height:460px;margin-top:12px"><table><thead><tr><th>Zone</th><th>Destination</th><th>Code</th><th class="num">Cost item</th><th class="num">Cost kg</th><th class="num">Sell item S$</th><th class="num">Sell kg S$</th><th class="num">Max Weight (KG)</th></tr></thead><tbody>
      ${rows.map(r=>`<tr><td>${esc(String(r.zone||""))}</td><td>${esc(String(r.name||_prcCName(r.code)||""))}</td><td>${esc(String(r.code||""))}</td><td class="num">${r.item==null?"—":r.item}</td><td class="num">${r.kg==null?"—":r.kg}</td><td class="num"><b>${r.sItem==null?"—":money(r.sItem)}</b></td><td class="num"><b>${r.sKg==null?"—":money(r.sKg)}</b></td><td class="num">${_PRC_EPAC.fiveKG.indexOf(r.code)>=0?5:2}</td></tr>`).join("")}
      </tbody></table></div></div>`;
  }
  const res=prSpdSell(P.spdMargin);
  return sub+`<div class="card"><div class="step">Pricing · QSM Speedpost</div><h3>Build a Speedpost DI (EU) sell rate card</h3>
    <p class="sub">Sell = ROUNDUP(SingPost cost × (1+margin), 2). Your CALC uses 5%; customer cards vary (e.g. Bpost Jul 26 ≈ 13.5%).</p>
    <div class="filters" style="display:flex;gap:10px;align-items:flex-end">
      <label>Margin %<br><input type="number" step="0.1" style="width:80px" value="${P.spdMargin}" onchange="prSetS('pqsm','spdMargin',Number(this.value))"></label>
      <label>Customer (file name)<br><input type="text" style="width:160px" placeholder="e.g. Bpost" value="${esc(P.custName||"")}" onchange="prInp('pqsm','custName',this.value)"></label>
      <button class="primary" onclick="prDlSpdCard()">⭳ Customer rate card</button>
      <button class="subtle" onclick="prDlSpdCalc()">⭳ CALC with formulas</button>
    </div>
    <div class="tbl-scroll" style="max-height:460px;margin-top:12px"><table><thead><tr><th>Weight ≤ kg</th>${res.countries.map(c=>`<th class="num">${esc(c)}</th>`).join("")}</tr></thead><tbody>
    ${res.weights.map((w,i)=>`<tr><td>${w}</td>${res.rows[i].map(v=>`<td class="num">${v==null?"—":money(v)}</td>`).join("")}</tr>`).join("")}
    </tbody></table></div></div>`;
}
function _prcCName(code){ return (typeof _CNAME!=="undefined"&&_CNAME[String(code||"").toUpperCase()])||""; }
function prQsmCostHtml(){
  const P=PRS.pqsm;
  const sub=`<div class="tabs" style="margin-bottom:12px">
    <button class="tab ${P.sub==='epac'?'active':''}" onclick="prSetS('pqsm','sub','epac')">ePAC</button>
    <button class="tab ${P.sub==='spd'?'active':''}" onclick="prSetS('pqsm','sub','spd')">Speedpost (SDI · EU)</button></div>`;
  if(P.sub==="epac"){
    const cost=prEpacCost();
    return sub+`<div class="card"><div class="step">Cost cards · QSM</div><h3>Linscomm ePAC cost (item + kg by country)</h3>
      <div style="display:flex;gap:10px;margin-bottom:8px"><button class="primary sm" onclick="prEpacCostSave()">✔ Save</button>
      <button class="subtle sm" onclick="prSet('epac_cost',null);render()">Reset</button></div>
      <div class="tbl-scroll" style="max-height:480px"><table id="prepaccost"><thead><tr><th>Zone</th><th>Destination</th><th>Code</th><th class="num">Item S$</th><th class="num">Kg S$</th></tr></thead><tbody>
      ${cost.map((r,i)=>`<tr><td><input type="text" style="width:44px" data-i="${i}" data-j="0" value="${esc(String(r[0]||""))}"></td><td>${esc(String(r[1]||_prcCName(r[2])||""))}</td><td>${esc(String(r[2]||""))}</td><td class="num"><input type="number" step="0.01" style="width:80px" data-i="${i}" data-j="3" value="${r[3]==null?"":r[3]}"></td><td class="num"><input type="number" step="0.01" style="width:80px" data-i="${i}" data-j="4" value="${r[4]==null?"":r[4]}"></td></tr>`).join("")}
      </tbody></table></div></div>`;
  }
  const d=prSpdCost();
  return sub+`<div class="card"><div class="step">Cost cards · QSM</div><h3>SingPost Speedpost DI cost (EU)</h3>
    <div style="display:flex;gap:10px;margin-bottom:8px"><button class="primary sm" onclick="prSpdCostSave()">✔ Save</button>
    <button class="subtle sm" onclick="prSet('spd_cost',null);prSet('spd_weights',null);render()">Reset</button></div>
    <div class="tbl-scroll" style="max-height:520px"><table id="prspdcost"><thead><tr><th>Weight ≤ kg</th>${d.countries.map(c=>`<th class="num">${esc(c)}</th>`).join("")}</tr></thead><tbody>
    ${d.weights.map((w,i)=>`<tr><td>${w}</td>${d.countries.map((c,j)=>`<td class="num"><input type="number" step="0.01" style="width:70px" data-i="${i}" data-j="${j}" value="${typeof d.cost[i][j]==="number"?d.cost[i][j]:""}"></td>`).join("")}</tr>`).join("")}
    </tbody></table></div></div>`;
}
