function _prToday(){ const d=new Date(); const M=["Jan","Feb","Mar","Apr","May","Jun","Jul","Aug","Sep","Oct","Nov","Dec"]; return M[d.getMonth()]+" "+d.getFullYear(); }
function _prSafe(s){ return String(s||"").replace(/[\/\\:*?\[\]"<>|]/g,"_").trim(); }
const _PRC_BRAND=["Amilo International Pte Ltd","Address: 150 Changi Road, Guthrie Building, Singapore, 419973","Hotline: +65 89348965","Website: www.shipx.asia"];
function _prColL(n){ let s=""; n=n+1; while(n){ const r=(n-1)%26; s=String.fromCharCode(65+r)+s; n=(n-1-r)/26|0; } return s; }
/* Rate Card Output_Template layout: company header + Service line + (row 9) Country Code/Country/Route/Max Weight/Delivery/PC Rate/KG Rate + weight grid, then a blank T&C sheet. */
function prBrandedRateWB(service, gridWeights, dataRows, extraSheets){
  const wb=XLSX.utils.book_new();
  const A=[];
  for(let i=0;i<4;i++) A.push([null,null,null,null,_PRC_BRAND[i]]);
  A.push([]); A.push([null,null,"Service: "+service]); A.push([]); A.push([]);
  const h=[null,"Country Code","Country","Route","Max Weight (KG)","Delivery Time (Est. Working Days)","PC Rate (SGD)","KG Rate (SGD)",null];
  gridWeights.forEach(w=>h.push(w));
  A.push(h);                                   // row 9 (header)
  dataRows.forEach(r=>{
    const R=A.length+1;
    const hasPcKg=(r.pc!=null||r.kg!=null);
    const pc=num(r.pc)||0, kg=num(r.kg)||0, mw=(r.maxw!=null?num(r.maxw):null);
    const line=[null,r.code||null,r.country||null,r.route||null,r.maxw==null?null:r.maxw,r.delivery||null,
      hasPcKg?{t:"n",v:pc,z:"0.000000"}:null, hasPcKg?{t:"n",v:kg,z:"0.000000"}:null, null];
    gridWeights.forEach((w,gi)=>{
      if(mw!=null && w>mw+1e-9){ line.push(null); return; }
      if(hasPcKg){ const col=_prColL(9+gi); line.push(fcell("$G"+R+"+$H"+R+"*"+col+"$9", round3(pc+kg*w), "0.000")); }
      else { const v=r.gridVals?r.gridVals[gi]:null; line.push((v==null||isNaN(v))?null:m2(v)); }
    });
    A.push(line);
  });
  XLSX.utils.book_append_sheet(wb,XLSX.utils.aoa_to_sheet(A),"Rates");
  (extraSheets||[]).forEach(s=>XLSX.utils.book_append_sheet(wb,XLSX.utils.aoa_to_sheet(s.aoa),s.name));
  const T=[];
  for(let i=0;i<4;i++) T.push([null,null,null,null,_PRC_BRAND[i]]);
  T.push([]); T.push([]); T.push([null,"Terms & Conditions"]);   // heading only — content left blank for the user
  XLSX.utils.book_append_sheet(wb,XLSX.utils.aoa_to_sheet(T),"T&C");
  wb.Workbook={CalcPr:{fullCalcOnLoad:true}};
  return wb;
}
const _PRC_LOGO_B64="";
function _b64ToU8(b64){ const bin=atob(b64), n=bin.length, u8=new Uint8Array(n); for(let i=0;i<n;i++) u8[i]=bin.charCodeAt(i); return u8; }
async function xlsxInjectLogo(u8, sheetIndex){
  if(typeof JSZip==="undefined" || !_PRC_LOGO_B64) return u8;
  try{
    const zip=await JSZip.loadAsync(u8);
    zip.file("xl/media/logoAmilo.png", _b64ToU8(_PRC_LOGO_B64));
    zip.file("xl/drawings/drawingLogo.xml",
      '<?xml version="1.0" encoding="UTF-8" standalone="yes"?>'+
      '<xdr:wsDr xmlns:xdr="http://schemas.openxmlformats.org/drawingml/2006/spreadsheetDrawing" xmlns:a="http://schemas.openxmlformats.org/drawingml/2006/main" xmlns:r="http://schemas.openxmlformats.org/officeDocument/2006/relationships">'+
      '<xdr:oneCellAnchor><xdr:from><xdr:col>2</xdr:col><xdr:colOff>1152525</xdr:colOff><xdr:row>0</xdr:row><xdr:rowOff>9525</xdr:rowOff></xdr:from>'+
      '<xdr:ext cx="1228725" cy="742950"/>'+
      '<xdr:pic><xdr:nvPicPr><xdr:cNvPr id="1" name="ShipX Logo"/><xdr:cNvPicPr/></xdr:nvPicPr>'+
      '<xdr:blipFill><a:blip r:embed="rId1"/><a:stretch><a:fillRect/></a:stretch></xdr:blipFill>'+
      '<xdr:spPr><a:prstGeom prst="rect"><a:avLst/></a:prstGeom></xdr:spPr></xdr:pic><xdr:clientData/></xdr:oneCellAnchor></xdr:wsDr>');
    zip.file("xl/drawings/_rels/drawingLogo.xml.rels",
      '<?xml version="1.0" encoding="UTF-8" standalone="yes"?><Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships"><Relationship Id="rId1" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/image" Target="../media/logoAmilo.png"/></Relationships>');
    const relPath="xl/worksheets/_rels/sheet"+sheetIndex+".xml.rels";
    let rels=zip.file(relPath)?await zip.file(relPath).async("string"):null, rid="rId1";
    if(rels){ const ids=(rels.match(/Id="rId(\d+)"/g)||[]).map(x=>+x.replace(/\D/g,"")); rid="rId"+((ids.length?Math.max.apply(null,ids):0)+1);
      rels=rels.replace("</Relationships>",'<Relationship Id="'+rid+'" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/drawing" Target="../drawings/drawingLogo.xml"/></Relationships>'); }
    else rels='<?xml version="1.0" encoding="UTF-8" standalone="yes"?><Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships"><Relationship Id="rId1" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/drawing" Target="../drawings/drawingLogo.xml"/></Relationships>';
    zip.file(relPath, rels);
    const sPath="xl/worksheets/sheet"+sheetIndex+".xml";
    let sx=await zip.file(sPath).async("string");
    if(sx.indexOf("xmlns:r=")<0) sx=sx.replace("<worksheet ", '<worksheet xmlns:r="http://schemas.openxmlformats.org/officeDocument/2006/relationships" ');
    if(sx.indexOf("<drawing ")<0) sx=sx.replace("</worksheet>", '<drawing r:id="'+rid+'"/></worksheet>');
    zip.file(sPath, sx);
    let ct=await zip.file("[Content_Types].xml").async("string");
    if(ct.indexOf('Extension="png"')<0) ct=ct.replace("<Default", '<Default Extension="png" ContentType="image/png"/><Default', 1);
    if(ct.indexOf("drawingLogo.xml")<0) ct=ct.replace("</Types>", '<Override PartName="/xl/drawings/drawingLogo.xml" ContentType="application/vnd.openxmlformats-officedocument.drawing+xml"/></Types>');
    zip.file("[Content_Types].xml", ct);
    return await zip.generateAsync({type:"array"});
  }catch(e){ console.error("logo inject failed", e); return u8; }
}
async function prSaveWB(wb, filename){
  const arr=XLSX.write(wb,{type:"array",bookType:"xlsx"});
  const out=await xlsxInjectLogo(arr, 1);   // Rates is sheet 1
  saveU8(new Uint8Array(out), filename);
}
