function prDlFdxCalc(){
  const P=PRS.pfedex, prod=P.prod, d=_PRC_FDX[prod], p=prFdxParams(prod), NT=prFdxNetTbl(prod);
  const wb=XLSX.utils.book_new();
  const zByName={}; d.zmap.forEach(m=>{ const k=String(m[0]).trim().toLowerCase(); if(zByName[k]===undefined) zByName[k]=m[1]; });
  const on="Origin Rate";
  const cost=[
    [null,null,null,"SGD","Currency Exchange",p.fx],
    [null,null,null,null,"Vendor Mark Up",p.vendor],
    [null,null,null,null,"Mark Up",p.margin],
    [null,null,null,null,"Clearance",p.clearanceKg],
    [null,null,null,null,"Origin Line haul (Per KG)",p.linehaulKg],
    [null,null,null,null,"Origin handling (Per Pc)",p.handlingPc],
    [null,null,null,null,"Pick Up (Per PC)",p.pickupPc],
    [null,null,null,null,"Pick Up (Per KG)",p.pickupKg],
    ["Country Code","Connect Plus?","Zone","Region","From Singapore"].concat(res9w(d)),
    []];
  function res9w(d){ return NT.weights.map(Number); }
  const zi={}; NT.zones.forEach((z,i)=>{ if(zi[String(z).trim().toUpperCase()]===undefined) zi[String(z).trim().toUpperCase()]=i; });
  const wi={}; NT.weights.forEach((w,i)=>{ if(wi[+w]===undefined) wi[+w]=i; });
  d.countries.forEach((c,k)=>{
    const zone=zByName[String(c[2]||"").trim().toLowerCase()]||"";
    const zii=zi[String(zone).trim().toUpperCase()];
    cost.push([c[0],c[1]?"Yes":"No",zone,null,c[2]].concat(NT.weights.map(Number).map(w=>{
      const i=wi[w]; if(zii==null||i==null) return null;
      const net=NT.net[i][zii]; return (typeof net==="number")?net:null; })));
  });
  XLSX.utils.book_append_sheet(wb,XLSX.utils.aoa_to_sheet(cost),"Cost");
  const colL=n=>{ let s=""; n=n+1; while(n){ const r=(n-1)%26; s=String.fromCharCode(65+r)+s; n=(n-1-r)/26|0; } return s; };
  const sell=[[],
    [null,"Fuel Surcharge",(prod==="PAK"||prod==="RET")?0.35:"exclude","changes every week"],
    [null,"Remote Area surcharge","may apply for AU and US"],
    [null,"Out of delivery area surcharge","may apply for AU and US"],
    [],
    [null,"From Singapore"].concat(NT.weights.map(Number))];
  const live=prFdxSell(prod);
  d.countries.forEach((c,k)=>{
    const R=7+k, costR=11+k;
    const row=[null,c[2]];
    NT.weights.forEach((w,j)=>{
      const costCol=colL(5+j);
      const wCol=colL(2+j);
      let f="((Cost!"+costCol+costR+"*(1+Cost!$F$2))+(Cost!$F$4*"+wCol+"$6)+(Cost!$F$5*"+wCol+"$6)+(Cost!$F$6)+(Cost!$F$7)+(Cost!$F$8*"+wCol+"$6))*(1+Cost!$F$3)*Cost!$F$1";
      if(d.rounded) f="round("+f+",2)";
      const v=live.rows[k]&&live.rows[k].vals[j];
      row.push({t:"n",f:f,v:(v==null||isNaN(v))?0:round2(v),z:"0.00"});
    });
    sell.push(row);
  });
  XLSX.utils.book_append_sheet(wb,XLSX.utils.aoa_to_sheet(sell),"Rates Exclude FS");
  const orr=[["Weight"],["Kgs"].concat(NT.zones)];
  NT.weights.forEach((w,i)=>orr.push([w].concat(NT.net[i])));
  XLSX.utils.book_append_sheet(wb,XLSX.utils.aoa_to_sheet(orr),on);
  XLSX.utils.book_append_sheet(wb,XLSX.utils.aoa_to_sheet([["Country/Territory","ICP","Country Code"]].concat(d.zmap.map(m=>[m[0],m[1],m[2]]))),"Zone");
  wb.Workbook={CalcPr:{fullCalcOnLoad:true}};
  const label=(_PRC_FDXPROD.find(x=>x[0]===prod)||[])[1]||prod;
  XLSX.writeFile(wb,_prSafe("Cost_CALC_FedEx ("+label+")_exSIN"+(P.custName?"_"+P.custName:"")+"_"+_prToday())+".xlsx");
}
