function prDlAmeCalc(){
  const P=PRS[route.id], orig=P.orig;
  const wb=XLSX.utils.book_new();
  const O=_PRC_AME.origins[orig];
  const hdr=O.header, F=O.formulas;
  const colN=L=>{ let n=0; for(const ch of L) n=n*26+ch.charCodeAt(0)-64; return n-1; };
  const maxC=85;
  const head=new Array(maxC).fill(null);
  Object.keys(hdr).forEach(L=>{ head[colN(L)]=hdr[L]; });
  const aoa=[[],head];
  const comp=prAmeCompute(orig);
  const compBy={}; comp.forEach(c=>compBy[c.r]=c);
  prAmeRows(orig).forEach((row,i)=>{
    const R=aoa.length+1;
    const line=new Array(maxC).fill(null);
    const IN=row.in||{}, CV=row.cv||{};
    Object.keys(IN).forEach(L=>{ line[colN(L)]=IN[L]; });
    Object.keys(CV).forEach(L=>{ if(line[colN(L)]==null) line[colN(L)]=CV[L]; });
    const cr=compBy[row.r];
    const CALCCOLS={R:1,AA:1,AB:1,AL:1,AU:1,AV:1,BC:1,BD:1,BF:1,BH:1,BI:1,BJ:1,BK:1,BL:1,BO:1,BP:1,BQ:1,BR:1,BS:1,BU:1,BV:1,BW:1,BX:1,BY:1,BZ:1,CA:1,CB:1,CC:1};
    Object.keys(F).forEach(L=>{
      if(!CALCCOLS[L]) return;
      if(CV[L]!==undefined) return;
      const pat=F[L]; if(pat.indexOf("Line Haul")>=0||pat.indexOf("COUNTIF")>=0) return;
      const f=pat.replace(/#/g,String(R));
      const val=cr?cr.out[L]:null;
      if(typeof val==="number") line[colN(L)]={t:"n",f:f,v:isFinite(val)?val:0,z:"0.0000"};
      else line[colN(L)]={t:"str",f:f,v:(val==null||val==="#ERR")?"":String(val)};
    });
    const cfCol=colN("CF"), cgCol=colN("CG");
    const m=1+prNum(P.margin)/100;
    if(cr){ line[cfCol]={t:"n",f:"BY"+R+"*"+m,v:prNum(cr.out.BY)*m,z:"0.0000"};
            line[cgCol]={t:"n",f:"BZ"+R+"*"+m,v:prNum(cr.out.BZ)*m,z:"0.0000"}; }
    aoa.push(line);
  });
  XLSX.utils.book_append_sheet(wb,XLSX.utils.aoa_to_sheet(aoa),"CALC."+orig);
  const T=prAmeTables();
  const mkSheet=rows=>{ const out=[]; rows.forEach(r=>{ const rn=r[0]; while(out.length<rn) out.push([]); out[rn-1]=r.slice(1); }); return XLSX.utils.aoa_to_sheet(out); };
  XLSX.utils.book_append_sheet(wb,mkSheet(T.combined),"COMBINED");
  XLSX.utils.book_append_sheet(wb,mkSheet(T.combinedU),"COMBINED (Unsorted)");
  XLSX.utils.book_append_sheet(wb,mkSheet(T.currency),"Currency SGD");
  XLSX.utils.book_append_sheet(wb,mkSheet(T.pickup),"Pick Up Charges");
  wb.Workbook={CalcPr:{fullCalcOnLoad:true}};
  XLSX.writeFile(wb,_prSafe("CALC.AME-"+orig+"_margin"+P.margin+"pct_"+_prToday())+".xlsx");
}
